document.querySelector("#show").addEventListener("click", () => {
  const name = document.querySelector("#name").value;
  const level = document.querySelector("#level").value;
  const agreed = document.querySelector("#agree").checked;
  console.log(`الاسم: ${name} | المستوى: ${level} | موافق: ${agreed}`);
});

document.querySelector("#f").addEventListener("submit", (e) => {
  e.preventDefault(); // لا تعد تحميل الصفحة
  const email = document.querySelector("#em").value.trim();
  document.querySelector("#msg").textContent =
    email ? `تم الاستلام: ${email}` : "الحقل فارغ!";
});

const form = document.querySelector("#reg");
form.addEventListener("submit", (e) => {
  e.preventDefault();
  const user = document.querySelector("#u").value.trim();
  const pass = document.querySelector("#p").value;
  const errors = [];

  if (user.length < 3) errors.push("الاسم 3 أحرف على الأقل");
  if (pass.length < 6) errors.push("كلمة المرور 6 أحرف على الأقل");

  const out = document.querySelector("#errs");
  if (errors.length) {
    out.style.color = "crimson";
    out.textContent = "⚠ " + errors.join(" — ");
  } else {
    out.style.color = "green";
    out.textContent = "✓ البيانات سليمة، تم التسجيل!";
  }
});
